     1→/**
     2→ * @dispatch/analytics - Anonymous telemetry for Dispatch
     3→ * 
     4→ * Usage:
     5→ * ```typescript
     6→ * import { createAnalytics, DispatchEvents } from '@dispatch/analytics';
     7→ * 
     8→ * const analytics = createAnalytics({
     9→ *   posthogKey: process.env.DISPATCH_POSTHOG_KEY!,
    10→ *   appVersion: '0.1.0',
    11→ *   clientType: 'desktop',
    12→ * });
    13→ * 
    14→ * analytics.record(DispatchEvents.APP_LAUNCHED, {
    15→ *   platform: process.platform,
    16→ * });
    17→ * 
    18→ * // On shutdown
    19→ * await analytics.shutdown();
    20→ * ```
    21→ * 
    22→ * Environment variables:
    23→ * - DISPATCH_POSTHOG_KEY: PostHog project API key
    24→ * - DISPATCH_POSTHOG_HOST: PostHog host (default: https://us.i.posthog.com)
    25→ * - DISPATCH_TELEMETRY_ENABLED: Enable/disable telemetry (default: true)
    26→ */
    27→
    28→export * from './types.js';
    29→export { createPostHogAnalytics } from './posthog.js';
    30→export { createNoopAnalytics, createMockAnalytics, type MockAnalyticsService } from './noop.js';
    31→export { getTelemetryIdentifier, clearTelemetryIdentifier } from './identify.js';
    32→
    33→import type { AnalyticsConfig, AnalyticsService } from './types.js';
    34→import { createPostHogAnalytics } from './posthog.js';
    35→import { createNoopAnalytics } from './noop.js';
    36→
    37→/**
    38→ * Create an analytics service based on configuration.
    39→ * 
    40→ * If telemetry is disabled (via config or environment), returns a no-op service.
    41→ * 
    42→ * Environment variables:
    43→ * - DISPATCH_TELEMETRY_ENABLED: Set to 'false' to disable telemetry
    44→ */
    45→export function createAnalytics(config: AnalyticsConfig): AnalyticsService {
    46→  // Check environment for telemetry disable
    47→  const envEnabled = process.env.DISPATCH_TELEMETRY_ENABLED;
    48→  const isEnabled = config.enabled !== false && envEnabled !== 'false';
    49→  
    50→  if (!isEnabled) {
    51→    return createNoopAnalytics();
    52→  }
    53→  
    54→  // Check for PostHog key
    55→  if (!config.posthogKey) {
    56→    console.warn('[analytics] No PostHog key provided, disabling telemetry');
    57→    return createNoopAnalytics();
    58→  }
    59→  
    60→  return createPostHogAnalytics(config);
    61→}
    62→
    63→/**
    64→ * Create analytics from environment variables.
    65→ * 
    66→ * Required environment variables:
    67→ * - DISPATCH_POSTHOG_KEY: PostHog project API key
    68→ * 
    69→ * Optional environment variables:
    70→ * - DISPATCH_POSTHOG_HOST: PostHog host (default: https://us.i.posthog.com)
    71→ * - DISPATCH_TELEMETRY_ENABLED: Enable/disable telemetry (default: true)
    72→ */
    73→export function createAnalyticsFromEnv(options: {
    74→  appVersion: string;
    75→  clientType: 'desktop' | 'cli';
    76→}): AnalyticsService {
    77→  const posthogKey = process.env.DISPATCH_POSTHOG_KEY;
    78→  
    79→  if (!posthogKey) {
    80→    console.warn('[analytics] DISPATCH_POSTHOG_KEY not set, disabling telemetry');
    81→    return createNoopAnalytics();
    82→  }
    83→  
    84→  return createAnalytics({
    85→    posthogKey,
