     1→/**
     2→ * Electron Main Process
     3→ *
     4→ * T3 Code Pattern:
     5→ * - Electron ALWAYS spawns the server as a child process
     6→ * - Dynamic port allocation (reserve before spawning)
     7→ * - Server lifecycle fully managed by Electron
     8→ * - Works identically in dev and packaged builds
     9→ */
    10→
    11→import { app, BrowserWindow, ipcMain, dialog } from "electron";
    12→import * as path from "path";
    13→import * as fs from "fs";
    14→import * as net from "net";
    15→import { spawn, type ChildProcess } from "child_process";
    16→import * as crypto from "crypto";
    17→import * as os from "os";
    18→import { fileURLToPath } from "url";
    19→
    20→const __filename = fileURLToPath(import.meta.url);
    21→const __dirname = path.dirname(__filename);
    22→
    23→// ============ Configuration ============
    24→
    25→const isDev = process.env.NODE_ENV === "development" || !app.isPackaged;
    26→
    27→// Separate identity for dev vs prod (allows running both simultaneously)
    28→const APP_NAME = isDev ? "Dispatch (Dev)" : "Dispatch";
    29→const USER_DATA_DIR = isDev ? "dispatch-dev" : "dispatch";
    30→
    31→const DEFAULT_SERVER_PORT = isDev ? 3333 : 3334; // Different ports for dev/prod
    32→const MAX_RESTART_ATTEMPTS = 5;
    33→const RESTART_BACKOFF_BASE_MS = 1000;
    34→const RESTART_BACKOFF_MAX_MS = 30000;
    35→const SERVER_STARTUP_TIMEOUT_MS = 15000;
    36→const STATE_DIR = path.join(os.homedir(), `.${USER_DATA_DIR}`);
    37→const LOG_DIR = path.join(STATE_DIR, "logs");
    38→
    39→// ============ State ============
    40→
    41→let mainWindow: BrowserWindow | null = null;
    42→let serverProcess: ChildProcess | null = null;
    43→let serverPort = 0; // Dynamically assigned
    44→let serverAuthToken = "";
    45→let restartAttempt = 0;
    46→let restartTimer: ReturnType<typeof setTimeout> | null = null;
    47→let isQuitting = false;
    48→
    49→// ============ Logging ============
    50→
    51→function ensureLogDir(): void {
    52→  try {
    53→    fs.mkdirSync(LOG_DIR, { recursive: true });
    54→  } catch {
    55→    // Ignore
    56→  }
    57→}
    58→
    59→function log(message: string, ...args: unknown[]): void {
    60→  const timestamp = new Date().toISOString();
    61→  const line = `[${timestamp}] [main] ${message}`;
    62→  console.log(line, ...args);
    63→  
    64→  try {
    65→    ensureLogDir();
    66→    fs.appendFileSync(
    67→      path.join(LOG_DIR, "main.log"),
    68→      `${line} ${args.map(a => JSON.stringify(a)).join(" ")}\n`
    69→    );
    70→  } catch {
    71→    // Ignore log write errors
    72→  }
    73→}
    74→
    75→// ============ Port Management ============
    76→
    77→/**
    78→ * Reserve a port by binding to it, then immediately closing.
    79→ * This is the T3 Code pattern - guarantees the port is available.
    80→ */
    81→async function reservePort(preferredPort: number = DEFAULT_SERVER_PORT): Promise<number> {
    82→  return new Promise((resolve, reject) => {
    83→    const server = net.createServer();
    84→    
    85→    server.once("error", (err: NodeJS.ErrnoException) => {
    86→      if (err.code === "EADDRINUSE") {
    87→        // Port in use, try next
    88→        server.close();
    89→        reservePort(preferredPort + 1).then(resolve).catch(reject);
    90→      } else {
    91→        reject(err);
    92→      }
    93→    });
    94→    
    95→    server.once("listening", () => {
    96→      const addr = server.address();
    97→      const port = typeof addr === "object" && addr !== null ? addr.port : preferredPort;
    98→      server.close(() => resolve(port));
    99→    });
   100→    
   101→    server.listen(preferredPort, "127.0.0.1");
   102→  });
   103→}
   104→
   105→// ============ Health Check ============
   106→
   107→async function waitForServerReady(port: number, maxMs: number = SERVER_STARTUP_TIMEOUT_MS): Promise<boolean> {
   108→  const start = Date.now();
   109→  while (Date.now() - start < maxMs) {
   110→    try {
   111→      const res = await fetch(`http://127.0.0.1:${port}/health`, {
   112→        signal: AbortSignal.timeout(1000),
   113→      });
   114→      if (res.ok) {
   115→        return true;
   116→      }
   117→    } catch {
   118→      // Not ready yet
   119→    }
   120→    await new Promise((r) => setTimeout(r, 200));
   121→  }
   122→  return false;
   123→}
   124→
   125→// ============ Server Lifecycle ============
   126→
   127→function resolveServerEntry(): string | null {
   128→  if (app.isPackaged) {
   129→    // Packaged: server bundle in Resources/server
   130→    const bundled = path.join(process.resourcesPath, "server", "dist", "run.js");
   131→    if (fs.existsSync(bundled)) {
   132→      return bundled;
   133→    }
   134→    log("Server entry not found at:", bundled);
   135→    return null;
   136→  }
   137→  
   138→  // Development: pre-built JavaScript (built by tsup --watch)
   139→  // This matches the T3 Code pattern - always run compiled JS, never TS directly
   140→  const serverDir = path.resolve(__dirname, "../../server");
   141→  const distEntry = path.join(serverDir, "dist", "run.js");
   142→  if (fs.existsSync(distEntry)) {
   143→    return distEntry;
   144→  }
   145→  
   146→  log("Server entry not found at:", distEntry);
   147→  log("Make sure server is building (turbo should run @acc/server dev)");
   148→  return null;
   149→}
   150→
   151→function resolveServerCwd(): string {
   152→  if (app.isPackaged) {
   153→    return path.join(process.resourcesPath, "server");
   154→  }
   155→  return path.resolve(__dirname, "../../server");
   156→}
   157→
   158→/**
   159→ * Build environment variables for the server process.
   160→ * Follows T3 Code pattern of passing config via env.
   161→ */
   162→function buildServerEnv(): NodeJS.ProcessEnv {
   163→  // Get monorepo root for node_modules/.bin
   164→  const monorepoRoot = path.resolve(__dirname, "../../..");
   165→  const nodeModulesBin = path.join(monorepoRoot, "node_modules", ".bin");
   166→  
   167→  // Augment PATH for GUI launches (Spotlight doesn't inherit shell PATH)
   168→  const extraPaths = [
   169→    nodeModulesBin,                              // monorepo binaries (tsx, etc.)
   170→    path.join(os.homedir(), ".local/bin"),       // claude CLI default location
   171→    path.join(os.homedir(), ".cargo/bin"),       // Rust tools
   172→    "/usr/local/bin",
   173→    "/opt/homebrew/bin",
   174→    path.join(os.homedir(), ".nvm/versions/node/v22.15.0/bin"),
   175→    path.join(os.homedir(), ".nvm/versions/node/v20.19.0/bin"),
   176→    path.join(os.homedir(), ".bun/bin"),
   177→  ].join(path.delimiter);
   178→
   179→  return {
   180→    ...process.env,
   181→    PATH: `${extraPaths}${path.delimiter}${process.env.PATH || ""}`,
   182→    ACC_MODE: "desktop",
   183→    ACC_SERVER_PORT: String(serverPort),
   184→    ACC_AUTH_TOKEN: serverAuthToken,
   185→    ACC_STATE_DIR: STATE_DIR,
   186→    ACC_NO_BROWSER: "1",
   187→    NODE_ENV: isDev ? "development" : "production",
   188→    FORCE_COLOR: "0",
   189→  };
   190→}
   191→
   192→async function startServer(): Promise<boolean> {
   193→  if (isQuitting || serverProcess) {
   194→    return false;
   195→  }
   196→
   197→  const serverEntry = resolveServerEntry();
   198→  if (!serverEntry) {
   199→    log("Cannot start server: entry point not found");
   200→    return false;
   201→  }
   202→
   203→  // Reserve port BEFORE spawning (T3 pattern)
   204→  try {
   205→    serverPort = await reservePort(DEFAULT_SERVER_PORT);
   206→    log(`Reserved port ${serverPort}`);
   207→  } catch (err) {
   208→    log("Failed to reserve port:", err);
   209→    return false;
   210→  }
   211→
   212→  // Generate auth token for this session
   213→  serverAuthToken = crypto.randomBytes(24).toString("hex");
   214→
   215→  const cwd = resolveServerCwd();
   216→  const env = buildServerEnv();
   217→  
   218→  log(`Starting server on port ${serverPort}...`);
   219→  log(`Server entry: ${serverEntry}`);
   220→  log(`Server cwd: ${cwd}`);
   221→
   222→  // T3 Code pattern: ALWAYS use Electron itself as Node runtime
   223→  // This works in both dev and production because server is pre-built to JS
   224→  const child = spawn(process.execPath, [serverEntry], {
   225→    cwd,
   226→    env: {
   227→      ...env,
   228→      ELECTRON_RUN_AS_NODE: "1",
   229→    },
   230→    stdio: ["ignore", "pipe", "pipe"],
   231→  });
   232→
   233→  serverProcess = child;
   234→
   235→  // Capture server output
   236→  ensureLogDir();
   237→  const serverLogPath = path.join(LOG_DIR, "server.log");
   238→  const serverLogStream = fs.createWriteStream(serverLogPath, { flags: "a" });
   239→  
   240→  const boundary = `\n=== Server started at ${new Date().toISOString()} pid=${child.pid} port=${serverPort} ===\n`;
   241→  serverLogStream.write(boundary);
   242→  
   243→  child.stdout?.on("data", (data) => {
   244→    serverLogStream.write(data);
   245→    if (isDev) {
   246→      process.stdout.write(`[server] ${data}`);
   247→    }
   248→  });
   249→  
   250→  child.stderr?.on("data", (data) => {
   251→    serverLogStream.write(data);
   252→    if (isDev) {
   253→      process.stderr.write(`[server] ${data}`);
   254→    }
   255→  });
   256→
   257→  child.once("spawn", () => {
   258→    log(`Server process spawned (pid=${child.pid})`);
   259→    restartAttempt = 0;
   260→  });
   261→
   262→  child.on("error", (error) => {
   263→    log("Server process error:", error.message);
   264→    if (serverProcess === child) {
   265→      serverProcess = null;
   266→    }
   267→    scheduleRestart(`error: ${error.message}`);
   268→  });
   269→
   270→  child.on("exit", (code, signal) => {
   271→    log(`Server process exited (code=${code}, signal=${signal})`);
   272→    serverLogStream.write(`\n=== Server exited code=${code} signal=${signal} ===\n`);
   273→    serverLogStream.end();
   274→    
   275→    if (serverProcess === child) {
   276→      serverProcess = null;
   277→    }
   278→    if (!isQuitting) {
   279→      scheduleRestart(`exit code=${code} signal=${signal}`);
   280→    }
   281→  });
   282→
   283→  // Wait for server to be ready
   284→  const ready = await waitForServerReady(serverPort);
   285→  if (ready) {
   286→    log("Server is ready");
   287→  } else {
   288→    log("Server did not become ready in time");
   289→  }
   290→  
   291→  return ready;
   292→}
   293→
   294→function scheduleRestart(reason: string): void {
   295→  if (isQuitting || restartTimer) {
   296→    return;
   297→  }
   298→
   299→  if (restartAttempt >= MAX_RESTART_ATTEMPTS) {
   300→    log(`Server restart limit reached (${MAX_RESTART_ATTEMPTS}), giving up`);
   301→    return;
   302→  }
   303→
   304→  const delayMs = Math.min(
   305→    RESTART_BACKOFF_BASE_MS * Math.pow(2, restartAttempt),
   306→    RESTART_BACKOFF_MAX_MS
   307→  );
   308→  restartAttempt++;
   309→
   310→  log(`Scheduling server restart in ${delayMs}ms (attempt ${restartAttempt}, reason: ${reason})`);
   311→  
   312→  restartTimer = setTimeout(async () => {
   313→    restartTimer = null;
   314→    const started = await startServer();
   315→    if (started) {
   316→      // Notify renderer of new server URL
   317→      mainWindow?.webContents.send("server-info", { 
   318→        port: serverPort,
   319→        apiUrl: `http://127.0.0.1:${serverPort}`,
   320→        wsUrl: `ws://127.0.0.1:${serverPort}`,
   321→      });
   322→    }
   323→  }, delayMs);
   324→}
   325→
   326→function stopServer(): void {
   327→  if (restartTimer) {
   328→    clearTimeout(restartTimer);
   329→    restartTimer = null;
   330→  }
   331→
   332→  const child = serverProcess;
   333→  serverProcess = null;
   334→  
   335→  if (!child) {
   336→    return;
   337→  }
   338→
   339→  log("Stopping server...");
   340→
   341→  // Try graceful shutdown first
   342→  if (child.exitCode === null && child.signalCode === null) {
   343→    child.kill("SIGTERM");
   344→    
   345→    // Force kill after timeout
   346→    setTimeout(() => {
   347→      if (child.exitCode === null && child.signalCode === null) {
   348→        log("Force killing server...");
   349→        child.kill("SIGKILL");
   350→      }
   351→    }, 2000);
   352→  }
   353→}
   354→
   355→// ============ Window Management ============
   356→
   357→function createWindow(): void {
   358→  // Set env vars BEFORE creating window so preload can access them
   359→  const apiUrl = `http://127.0.0.1:${serverPort}`;
   360→  const wsUrl = `ws://127.0.0.1:${serverPort}`;
   361→  process.env.ACC_SERVER_API_URL = apiUrl;
   362→  process.env.ACC_SERVER_WS_URL = wsUrl;
   363→  
   364→  log(`Server URLs: API=${apiUrl} WS=${wsUrl}`);
   365→
   366→  mainWindow = new BrowserWindow({
   367→    title: APP_NAME,
   368→    width: 1400,
   369→    height: 900,
   370→    minWidth: 1000,
   371→    minHeight: 600,
   372→    titleBarStyle: "hiddenInset",
   373→    trafficLightPosition: { x: 16, y: 16 },
   374→    webPreferences: {
   375→      nodeIntegration: false,
   376→      contextIsolation: true,
   377→      preload: path.join(__dirname, "preload.js"),
   378→    },
   379→  });
   380→
   381→  if (isDev) {
   382→    // In dev, load from Vite dev server
   383→    const viteUrl = process.env.VITE_DEV_SERVER_URL || "http://localhost:5173";
   384→    mainWindow.loadURL(viteUrl);
   385→    mainWindow.webContents.openDevTools();
   386→  } else {
   387→    mainWindow.loadFile(path.join(__dirname, "../dist/index.html"));
   388→  }
   389→
   390→  mainWindow.on("closed", () => {
   391→    mainWindow = null;
   392→  });
   393→
   394→  // Send server info once page loads
   395→  mainWindow.webContents.on("did-finish-load", () => {
   396→    mainWindow?.webContents.send("server-info", { 
   397→      port: serverPort,
   398→      apiUrl,
   399→      wsUrl,
   400→    });
   401→  });
   402→}
   403→
   404→async function bootstrap(): Promise<void> {
   405→  log("Bootstrap starting...");
   406→  
   407→  // Always start our own server (T3 pattern - no checking for existing)
   408→  const serverStarted = await startServer();
   409→  if (!serverStarted) {
   410→    log("Warning: Server failed to start, app may not work correctly");
   411→  }
   412→  
   413→  createWindow();
   414→  log("Bootstrap complete");
   415→}
   416→
   417→// ============ App Identity (Dev vs Prod) ============
   418→
   419→// Set app name and user data path BEFORE requesting single instance lock
   420→// This allows dev and prod to run simultaneously
   421→app.name = APP_NAME;
   422→app.setPath("userData", path.join(os.homedir(), "Library", "Application Support", USER_DATA_DIR));
   423→
   424→log(`App identity: ${APP_NAME} (isDev=${isDev})`);
   425→log(`User data: ${app.getPath("userData")}`);
   426→
   427→// ============ Single Instance ============
   428→
   429→// Use different instance lock names for dev vs prod
   430→const gotSingleInstanceLock = app.requestSingleInstanceLock({ key: USER_DATA_DIR });
   431→
   432→if (!gotSingleInstanceLock) {
   433→  app.quit();
   434→} else {
   435→  app.on("second-instance", () => {
   436→    if (mainWindow) {
   437→      if (mainWindow.isMinimized()) mainWindow.restore();
   438→      mainWindow.focus();
   439→    }
   440→  });
   441→}
   442→
   443→// ============ App Lifecycle ============
   444→
   445→app.whenReady().then(() => {
   446→  bootstrap().catch((error) => {
   447→    log("Bootstrap failed:", error);
   448→    dialog.showErrorBox("Dispatch failed to start", String(error));
   449→    app.quit();
   450→  });
   451→
   452→  app.on("activate", () => {
   453→    if (BrowserWindow.getAllWindows().length === 0) {
   454→      bootstrap();
   455→    }
   456→  });
   457→});
   458→
   459→app.on("before-quit", () => {
   460→  isQuitting = true;
   461→  stopServer();
   462→});
   463→
   464→app.on("window-all-closed", () => {
   465→  if (process.platform !== "darwin") {
   466→    app.quit();
   467→  }
   468→});
   469→
   470→// Handle SIGINT/SIGTERM for clean shutdown
   471→if (process.platform !== "win32") {
   472→  process.on("SIGINT", () => {
   473→    if (isQuitting) return;
   474→    isQuitting = true;
   475→    stopServer();
   476→    app.quit();
   477→  });
   478→  
   479→  process.on("SIGTERM", () => {
   480→    if (isQuitting) return;
   481→    isQuitting = true;
   482→    stopServer();
   483→    app.quit();
   484→  });
   485→}
   486→
   487→// ============ IPC Handlers ============
   488→
   489→// Sync handler for preload to get server URLs
   490→ipcMain.on("server:get-urls", (event) => {
   491→  event.returnValue = {
   492→    apiUrl: `http://127.0.0.1:${serverPort}`,
   493→    wsUrl: `ws://127.0.0.1:${serverPort}`,
   494→  };
   495→});
   496→
   497→// Get server info
   498→ipcMain.handle("server:info", () => {
   499→  return { 
   500→    port: serverPort, 
   501→    pid: serverProcess?.pid,
   502→    apiUrl: `http://127.0.0.1:${serverPort}`,
   503→    wsUrl: `ws://127.0.0.1:${serverPort}`,
   504→  };
   505→});
   506→
   507→// Restart server (for debugging/recovery)
   508→ipcMain.handle("server:restart", async () => {
   509→  log("Manual server restart requested");
   510→  stopServer();
   511→  await new Promise(r => setTimeout(r, 500));
   512→  return startServer();
   513→});
   514→
   515→// Adapter management
   516→ipcMain.handle(
   517→  "adapter:connect",
   518→  async (_event, adapterId: string, config: unknown) => {
   519→    log("Connecting adapter:", adapterId);
   520→    return { ok: true };
   521→  }
   522→);
   523→
   524→ipcMain.handle("adapter:disconnect", async (_event, adapterId: string) => {
   525→  log("Disconnecting adapter:", adapterId);
   526→  return { ok: true };
   527→});
   528→
   529→ipcMain.handle(
   530→  "adapter:send",
   531→  async (_event, adapterId: string, message: string) => {
   532→    log("Sending to adapter:", adapterId);
   533→    return { ok: true, turnId: crypto.randomUUID() };
   534→  }
   535→);
   536→
   537→// Launchers
   538→ipcMain.handle("launcher:cursor", async (_event, projectPath: string) => {
   539→  const { exec } = await import("child_process");
   540→  return new Promise((resolve, reject) => {
   541→    exec(`cursor "${projectPath}"`, (error) => {
   542→      if (error) reject(error);
   543→      else resolve({ ok: true });
   544→    });
   545→  });
   546→});
   547→
   548→ipcMain.handle("launcher:browser", async (_event, url: string) => {
   549→  const { shell } = await import("electron");
