    21→const uiRoot = join(__dirname, '..');
    22→const serverDir = join(root, 'packages/server');
    23→const contractsDir = join(root, 'packages/contracts');
    24→const bundleDir = join(uiRoot, 'server-bundle');
    25→
    26→async function main() {
    27→  console.log('📦 Preparing server bundle for packaged app (T3 pattern)...');
    28→
    29→  // Clean and create bundle directory
    30→  await rm(bundleDir, { recursive: true }).catch(() => {});
    31→  await mkdir(bundleDir, { recursive: true });
    32→
    33→  // 1. Copy server dist
    34→  console.log('  → Copying server dist...');
    35→  await cp(join(serverDir, 'dist'), join(bundleDir, 'dist'), { recursive: true });
    36→
    37→  // 2. Create package.json (strip workspace: deps and devDeps)
    38→  console.log('  → Creating package.json...');
    39→  const serverPkg = JSON.parse(await readFile(join(serverDir, 'package.json'), 'utf-8'));
    40→  
    41→  const bundlePkg = {
    42→    name: serverPkg.name,
    43→    version: serverPkg.version,
    44→    type: 'module',
    45→    main: './dist/run.js',
    46→    scripts: { start: 'node dist/run.js' },
    47→    dependencies: {},
    48→  };
    49→
    50→  // Copy non-workspace dependencies
    51→  for (const [name, version] of Object.entries(serverPkg.dependencies || {})) {
    52→    if (!version.startsWith('workspace:')) {
