    60→  // npm handles native module compilation correctly for Electron
    61→  console.log('  → Installing production dependencies (npm)...');
    62→  execSync('npm install --omit=dev --legacy-peer-deps', {
    63→    cwd: bundleDir,
    64→    stdio: 'inherit',
    65→  });
    66→
    67→  // 4. Inline @acc/contracts (since it was a workspace: dep)
    68→  console.log('  → Inlining @acc/contracts...');
    69→  const contractsTarget = join(bundleDir, 'node_modules/@acc/contracts');
    70→  await rm(contractsTarget, { recursive: true }).catch(() => {});
    71→  await mkdir(join(contractsTarget, 'dist'), { recursive: true });
    72→  await cp(join(contractsDir, 'dist'), join(contractsTarget, 'dist'), { recursive: true });
    73→  
    74→  const contractsPkg = JSON.parse(await readFile(join(contractsDir, 'package.json'), 'utf-8'));
    75→  await writeFile(join(contractsTarget, 'package.json'), JSON.stringify({
    76→    name: contractsPkg.name,
    77→    version: contractsPkg.version,
    78→    type: 'module',
    79→    main: './dist/index.js',
    80→  }, null, 2));
    81→
    82→  // 5. Rebuild native modules for Electron
    83→  console.log('  → Rebuilding native modules for Electron...');
    84→  try {
    85→    // Get Electron version from ui package
    86→    const uiPkg = JSON.parse(await readFile(join(uiRoot, 'package.json'), 'utf-8'));
    87→    const electronVersion = uiPkg.dependencies?.electron || uiPkg.devDependencies?.electron || '40.0.0';
    88→    const cleanVersion = electronVersion.replace(/[\^~]/, '');
    89→    
    90→    execSync(`npx @electron/rebuild --version=${cleanVersion} --module-dir=.`, {
    91→      cwd: bundleDir,
    92→      stdio: 'inherit',
    93→    });
    94→    console.log('  ✓ Native modules rebuilt for Electron');
    95→  } catch (err) {
    96→    console.warn('  ⚠ electron-rebuild failed, electron-builder will retry during packaging');
    97→  }
    98→
    99→  console.log('✅ Server bundle ready at packages/ui/server-bundle');
   100→}
   101→
   102→main().catch((err) => {
   103→  console.error('❌ Bundle preparation failed:', err);
   104→  process.exit(1);
   105→});
